(function () {
    var COOKIE = 'fq_favorites';
    var DAYS = 365;
    var isLogged = typeof fqFav !== 'undefined' && fqFav.logged === '1';
    var nonce = typeof fqFav !== 'undefined' ? fqFav.nonce : '';
    var ajaxUrl = typeof fqFav !== 'undefined' ? fqFav.ajax : '';

    /* ── Cookie helpers ──────────────────────────────────────── */
    function getCookie() {
        var match = document.cookie.match(/(?:^|;\s*)fq_favorites=([^;]*)/);
        if (!match) { return []; }
        try { return JSON.parse(decodeURIComponent(match[1])); } catch (e) { return []; }
    }

    function setCookie(ids) {
        var expires = new Date();
        expires.setDate(expires.getDate() + DAYS);
        document.cookie = COOKIE + '=' + encodeURIComponent(JSON.stringify(ids)) + '; expires=' + expires.toUTCString() + '; path=/; SameSite=Lax';
    }

    /* ── API helpers (usuario logado) ────────────────────────── */
    function apiRequest(action, productId, cb) {
        var xhr = new XMLHttpRequest();
        xhr.open('POST', ajaxUrl, true);
        xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
        xhr.onreadystatechange = function () {
            if (xhr.readyState === 4) {
                try { var r = JSON.parse(xhr.responseText); cb(r); } catch (e) { cb(null); }
            }
        };
        xhr.send('action=fq_favorites&fq_action=' + action + '&product_id=' + productId + '&nonce=' + nonce);
    }

    /* ── Estado: obtener IDs favoritos ───────────────────────── */
    function getFavorites(cb) {
        if (isLogged) {
            apiRequest('get', 0, function (r) {
                cb(r && r.success ? r.data : []);
            });
        } else {
            cb(getCookie());
        }
    }

    /* ── Toggle ──────────────────────────────────────────────── */
    function toggle(productId, btn, cb) {
        productId = parseInt(productId, 10);
        if (isLogged) {
            apiRequest('toggle', productId, function (r) {
                if (r && r.success) { cb(r.data.active); }
            });
        } else {
            var ids = getCookie();
            var idx = ids.indexOf(productId);
            var active;
            if (idx === -1) { ids.push(productId); active = true; }
            else { ids.splice(idx, 1); active = false; }
            setCookie(ids);
            cb(active);
        }
    }

    /* ── Actualizar badge del header ─────────────────────────── */
    function updateHeaderBadge(count) {
        var badge = document.querySelector('.fq-fav-count-badge');
        if (!badge) { return; }
        badge.textContent = count > 0 ? String(count) : '';
        if (count > 0) { badge.classList.remove('is-empty'); }
        else { badge.classList.add('is-empty'); }
    }

    /* ── Aplicar estado visual al botón ─────────────────────── */
    function applyState(btn, active) {
        if (active) {
            btn.classList.add('is-active');
            btn.setAttribute('aria-pressed', 'true');
        } else {
            btn.classList.remove('is-active');
            btn.setAttribute('aria-pressed', 'false');
        }
    }

    /* ── Inicializar botones en la página ────────────────────── */
    function init() {
        var btns = document.querySelectorAll('[data-fq-fav]');
        if (!btns.length) { return; }

        getFavorites(function (ids) {
            ids = ids.map(function (id) { return parseInt(id, 10); });
            updateHeaderBadge(ids.length);
            btns.forEach(function (btn) {
                var pid = parseInt(btn.getAttribute('data-fq-fav'), 10);
                applyState(btn, ids.indexOf(pid) !== -1);

                btn.addEventListener('click', function (e) {
                    e.preventDefault();
                    e.stopPropagation();
                    toggle(pid, btn, function (active) {
                        applyState(btn, active);
                        document.querySelectorAll('[data-fq-fav="' + pid + '"]').forEach(function (b) {
                            applyState(b, active);
                        });
                        getFavorites(function (newIds) {
                            updateHeaderBadge(newIds.length);
                        });
                    });
                });
            });
        });
    }

    /* ── Selector de visualización en página de favoritos ───────── */
    function initFavGrid() {
        var btns = document.querySelectorAll('.fq-fav-grid-btn');
        var styleEl = document.getElementById('fq-fav-grid-style');
        if (!btns.length || !styleEl) { return; }
        var LS_KEY = 'fq_fav_grid';
        var saved = localStorage.getItem(LS_KEY);
        if (saved) { applyGrid(parseInt(saved, 10)); }
        btns.forEach(function (btn) {
            btn.addEventListener('click', function () {
                var cols = parseInt(btn.getAttribute('data-fav-grid'), 10);
                btns.forEach(function (b) { b.classList.remove('active'); });
                btn.classList.add('active');
                applyGrid(cols);
                localStorage.setItem(LS_KEY, String(cols));
            });
        });
        function applyGrid(cols) {
            btns.forEach(function (b) {
                b.classList.toggle('active', parseInt(b.getAttribute('data-fav-grid'), 10) === cols);
            });
            styleEl.textContent =
                '@media (min-width: 1025px){' +
                '.fq-favorites-page ul.products{grid-template-columns:repeat(' + cols + ',1fr)!important;}' +
                '}';
        }
    }

    /* ── Click en tarjeta → navegar al producto ──────────────── */
    function initCardLinks() {
        document.querySelectorAll('[data-fq-card-url]').forEach(function (card) {
            card.style.cursor = 'pointer';
            card.addEventListener('click', function (e) {
                if (e.target.closest('.fq-fav-btn') || e.target.closest('.fp-card__cta') || e.target.closest('.bs-card__cta') || e.target.closest('a')) {
                    return;
                }
                var url = card.getAttribute('data-fq-card-url');
                if (url) { window.location.href = url; }
            });
        });
    }

    function initBadge() {
        getFavorites(function (ids) { updateHeaderBadge(ids.length); });
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', function () { initBadge(); init(); initCardLinks(); initFavGrid(); });
    } else {
        initBadge();
        init();
        initCardLinks();
        initFavGrid();
    }

    /* ── Re-inicializar tras AJAX de SuperPlus ───────────────── */
    var observer = new MutationObserver(function () {
        var newBtns = document.querySelectorAll('[data-fq-fav]:not([data-fq-fav-init])');
        if (!newBtns.length) { return; }
        newBtns.forEach(function (b) { b.setAttribute('data-fq-fav-init', '1'); });
        getFavorites(function (ids) {
            ids = ids.map(function (id) { return parseInt(id, 10); });
            newBtns.forEach(function (btn) {
                var pid = parseInt(btn.getAttribute('data-fq-fav'), 10);
                applyState(btn, ids.indexOf(pid) !== -1);
                btn.addEventListener('click', function (e) {
                    e.preventDefault();
                    e.stopPropagation();
                    toggle(pid, btn, function (active) {
                        document.querySelectorAll('[data-fq-fav="' + pid + '"]').forEach(function (b) {
                            applyState(b, active);
                        });
                    });
                });
            });
        });
    });
    observer.observe(document.body, { childList: true, subtree: true });
})();
